import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),o={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F16_大股東成本與籌碼結構審計_投資研究員.md"};function l(i,t,s,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="f16-大股東成本與籌碼結構審計-投資研究員審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>瀚荃董監持股約11.13%，質押比例0%，屬利益深度綑綁且零槓桿風險型態。千張大戶佔比50.52%（12週+1.41pp）、400張以上達59.54%（3年累計+6.36pp），籌碼結構呈現強勢手集中特徵，支撐力道強勁。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A（良）</strong></p><p>評級依據：</p><ul><li>董監持股 11.13%，雖未達 25% 的 S 級門檻，但考量公司為上市櫃連接器中實股，此水準在電子零組件產業已屬中上</li><li><strong>全體董監質押比例 0%</strong>，不存在任何斷頭平倉風險，這是本題最核心的安全錨點</li><li>千張大戶持股 50.52% 且持續上升，籌碼由強勢手主導</li><li>傳凱投資法人董事解任為扣分項，需持續監控是否引發連鎖減持</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、董監事持股結構" tabindex="-1">一、董監事持股結構 <a class="header-anchor" href="#一、董監事持股結構" aria-label="Permalink to &quot;一、董監事持股結構&quot;">​</a></h3><p><strong>持股趨勢</strong>：董監持股從2025/12的11.43%緩降至2026/03的11.13%（-0.30pp），主因為股本膨脹稀釋及法人股權轉讓，非大規模出脫。在電子零組件產業中屬中等偏上水準。</p><p><strong>質押安全性</strong>：全體董監質押比例為0%，為最高級防護。即使股價回檔50%至48元，零質押曝險，不存在平倉連鎖風險。</p><p><strong>內部人申轉紀錄</strong>：楊奕康2025/02申報轉讓200張（佔持股39.2%），屬個人理財調節；楊超群歷年多次1,300張申轉推測為特定理財用途。整體頻率低、數量有限，不構成系統性看淡信號。</p><p><strong>法人董事解任事件</strong>：傳凱投資因轉讓持股超標於2026/04/02當然解任，需補選董事，短期治理結構調整，但不代表經營團隊信心減弱。</p><h3 id="二、股權分散表分析" tabindex="-1">二、股權分散表分析 <a class="header-anchor" href="#二、股權分散表分析" aria-label="Permalink to &quot;二、股權分散表分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th style="text-align:center;">2023/04</th><th style="text-align:center;">最新(2026/04/24)</th><th style="text-align:center;">變化</th></tr></thead><tbody><tr><td>千張大戶佔比</td><td style="text-align:center;">45.90%</td><td style="text-align:center;">50.52%</td><td style="text-align:center;">+4.62pp</td></tr><tr><td>400張以上佔比</td><td style="text-align:center;">53.18%</td><td style="text-align:center;">59.54%</td><td style="text-align:center;">+6.36pp</td></tr><tr><td>散戶佔比(&lt;1張)</td><td style="text-align:center;">2.31%</td><td style="text-align:center;">1.93%</td><td style="text-align:center;">-0.38pp</td></tr><tr><td>散戶人數</td><td style="text-align:center;">~6,950</td><td style="text-align:center;">10,875</td><td style="text-align:center;">+56.5%</td></tr></tbody></table><p>近12週千張大戶+1.41pp、400張以上+2.31pp，籌碼集中化持續強化。散戶人數雖暴增但持股佔比下降，代表新增者多為極小額買家，其持倉不足以撼動結構。</p><h3 id="三、大股東持股成本估算" tabindex="-1">三、大股東持股成本估算 <a class="header-anchor" href="#三、大股東持股成本估算" aria-label="Permalink to &quot;三、大股東持股成本估算&quot;">​</a></h3><p>群康投資（持股7,044張）為創始核心股東，成本區間15-30元，目前股價約95元，溢價3-6倍，即便腰斬至50元仍深度獲利。楊奕康成本區間40-60元，若股價回檔至該區間可能觸發持股保衛行為。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="空頭視角-最極端的風險阻力" tabindex="-1">空頭視角：最極端的風險阻力 <a class="header-anchor" href="#空頭視角-最極端的風險阻力" aria-label="Permalink to &quot;空頭視角：最極端的風險阻力&quot;">​</a></h3><ol><li><strong>傳凱解任的骨牌效應</strong>：法人董事因轉讓超標解任，若其他法人跟進減持，董監持股比例可能滑落至個位數，觸發治理信心危機。惟目前其他董監事無類似舉動，機率低。</li><li><strong>散戶人數暴增的隱憂</strong>：近12週散戶人數從6,950人增至10,875人（+56.5%），急速膨脹通常是股價高位吸引的投機資金。一旦回檔，停損賣壓將成短線賣方主力。</li><li><strong>楊奕康持續申轉風險</strong>：若未來6個月再度申報轉讓（每次200張以上），需升級為「系統性減持」警訊，屆時修正評級至B級。</li></ol><h3 id="物理對策" tabindex="-1">物理對策 <a class="header-anchor" href="#物理對策" aria-label="Permalink to &quot;物理對策&quot;">​</a></h3><ul><li><strong>防守線1</strong>：董監持股跌破10%，啟動治理風險紅燈</li><li><strong>防守線2</strong>：楊奕康半年內二度申轉，視為內部人信心減弱</li><li><strong>防守線3</strong>：千張大戶佔比跌破47%，籌碼由集中轉向渙散</li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><strong>FinMind TaiwanStockShareholdingSpread</strong>：調用 <code>backer_holding 8103 2023-04-25 2026-04-25 --df</code>，取得 2023/04 至 2026/04 共 157 週股權分散表數據</li><li><strong>FinMind TaiwanStockInstitutionalHolding</strong>：調用 <code>holding 8103 2023-04-25 2026-04-25 --df</code>，取得外資持股趨勢（7.88% → 25.85%）</li><li><strong>散戶鬥嘴鼓（poorstock.com）</strong>：8103 董監持股明細，全體董監質押比例 0%，群康投資持股 7,043,600 股</li><li><strong>財報狗（statementdog.com）</strong>：董監持股比例月趨勢（2025/12 的 11.43% → 2026/03 的 11.13%）</li><li><strong>PChome 股市（megatime.com.tw）</strong>：申報轉讓紀錄，楊奕康 2025/02/19 申報 200 張</li><li><strong>Yahoo 股市</strong>：傳凱投資法人董事因轉讓超標解任公告（2026/04/02）</li></ol><hr><p><strong>報告產出日期</strong>：2026-04-25 <strong>數據截止日</strong>：2026-04-24（股權分散表）/ 2026-04-24（外資持股） <strong>專家身分</strong>：投資研究員（Finance Investment Researcher） <strong>審計協議版本</strong>：v5.1 Protocol-Linked</p>',29)])])}const _=e(o,[["render",l]]);export{p as __pageData,_ as default};
